-- Services local Players = game:GetService("Players") local RunService = game:GetService("RunService") local TweenService = game:GetService("TweenService") local UserInputService = game:GetService("UserInputService") local ReplicatedStorage = game:GetService("ReplicatedStorage") local HttpService = game:GetService("HttpService") local plr = Players.LocalPlayer local camera = workspace.CurrentCamera -- ══════════════════════════════════════════ -- State -- ══════════════════════════════════════════ local state = {     NoRecoil=false, NoSpread=false, AutoDrop=false, ESP=false,     ThirdPerson=false, AntiKatana=false, NoBounds=false,     JumpBug=false, AutoStrafe=false, RapidFire=false,     AutoWeapon=false, InstantScope=false, AlwaysBackstab=false,     RemoveKillers=false, NoFireDamage=false, AntiFreeze=false,     Fly=false, Noclip=false, AntiAim=false, AutoFarm=false, } local settings = { WalkSpeed=16, JumpPower=50, StrafeIntensity=50, FlySpeed=50 } local farmPosition = "Behind" -- ══════════════════════════════════════════ -- GC Cache -- ══════════════════════════════════════════ local cachedTables = {} local function findAndCache(attribute)     if cachedTables[attribute] then return end     cachedTables[attribute] = {}     for _, gcVal in pairs(getgc(true)) do         if type(gcVal) == "table" and rawget(gcVal, attribute) ~= nil then             table.insert(cachedTables[attribute], { tbl=gcVal, original=gcVal[attribute] })         end     end end local function applyAttribute(attribute, value)     findAndCache(attribute)     if type(cachedTables[attribute]) ~= "table" then return end     for _, entry in pairs(cachedTables[attribute]) do         if type(entry) == "table" and entry.tbl then             pcall(function() entry.tbl[attribute] = value end)         end     end end local function restoreAttribute(attribute)     if not cachedTables[attribute] then return end     if type(cachedTables[attribute]) ~= "table" then cachedTables[attribute]=nil return en
